func TestNovelUpsertNormalizePerson(t *testing.T) {
	// Scalar email must become emails:[{email, category:"work"}].
	body := normalizePerson(map[string]any{"name": "Ann", "email": "ann@x.com"})
	if _, hasScalar := body["email"]; hasScalar {
		t.Error("normalized person should not retain scalar email")
	}
	emails, ok := body["emails"].([]map[string]any)
	if !ok || len(emails) != 1 {
		t.Fatalf("emails = %#v, want one-element slice", body["emails"])
	}
	if emails[0]["email"] != "ann@x.com" || emails[0]["category"] != "work" {
		t.Errorf("email entry = %#v, want {ann@x.com work}", emails[0])
	}

	// A lead keeps the scalar email shape.
	lead := normalizeLead(map[string]any{"name": "Biz", "email": "biz@x.com"})
	if lead["email"] != "biz@x.com" {
		t.Errorf("lead email = %#v, want scalar biz@x.com", lead["email"])
	}
}

func TestNovelUpsertBuildPlan(t *testing.T) {
	plan, err := buildUpsertPlan("person", "email", []map[string]any{
		{"name": "Ann", "email": "ann@x.com"},
		{"name": "Bob", "email": "bob@x.com"},
	})
	if err != nil {
		t.Fatalf("buildUpsertPlan: %v", err)
	}
	if len(plan) != 2 {
		t.Fatalf("plan len = %d, want 2", len(plan))
	}
	if plan[0].Match != "ann@x.com" || plan[0].Action != "create" {
		t.Errorf("plan[0] = %+v", plan[0])
	}

	// Missing match field is an error.
	if _, err := buildUpsertPlan("person", "email", []map[string]any{{"name": "NoEmail"}}); err == nil {
		t.Error("buildUpsertPlan should error on missing match field")
	}
}

// fakeUpsertClient simulates fetch_by_email (existing vs not) + create/update.
type fakeUpsertClient struct {
	existing map[string]string // email -> id
	posts    []string
	puts     []string
}

func (f *fakeUpsertClient) Post(ctx context.Context, path string, body any) (json.RawMessage, int, error) {
	if path == "/people/fetch_by_email" {
		m, _ := body.(map[string]any)
		email, _ := m["email"].(string)
		if id, ok := f.existing[email]; ok {
			return json.RawMessage(`{"id":` + id + `}`), 200, nil
		}
		return nil, 404, nil
	}
	f.posts = append(f.posts, path)
	return json.RawMessage(`{"id":1}`), 200, nil
}

func (f *fakeUpsertClient) Put(ctx context.Context, path string, body any) (json.RawMessage, int, error) {
	f.puts = append(f.puts, path)
	return json.RawMessage(`{}`), 200, nil
}

func TestNovelUpsertRunCreateVsUpdate(t *testing.T) {
	c := &fakeUpsertClient{existing: map[string]string{"ann@x.com": "55"}}
	plan, _ := buildUpsertPlan("person", "email", []map[string]any{
		{"name": "Ann", "email": "ann@x.com"}, // exists -> update
		{"name": "Bob", "email": "bob@x.com"}, // new -> create
	})
	summary := runUpsert(context.Background(), c, "person", "email", plan)
	if summary.Updated != 1 || summary.Created != 1 {
		t.Errorf("summary = %+v, want 1 created / 1 updated", summary)
	}
	if len(c.puts) != 1 || !strings.Contains(c.puts[0], "/people/55") {
		t.Errorf("PUT calls = %v, want one to /people/55", c.puts)
	}
}

func TestNovelUpsertLeadUsesServerUpsert(t *testing.T) {
	c := &fakeUpsertClient{}
	plan, err := buildUpsertPlan("lead", "email", []map[string]any{
		{"name": "Biz", "email": "biz@x.com"},
	})
	if err != nil {
		t.Fatalf("buildUpsertPlan lead: %v", err)
	}
	summary := runUpsert(context.Background(), c, "lead", "email", plan)
	if summary.Updated != 1 || summary.Created != 0 || len(summary.Failures) != 0 {
		t.Errorf("summary = %+v, want 1 updated / 0 created / 0 failures", summary)
	}
	if len(c.puts) != 1 || c.puts[0] != "/leads/upsert" {
		t.Errorf("PUT calls = %v, want one to /leads/upsert", c.puts)
	}
	if len(c.posts) != 0 {
		t.Errorf("POST calls = %v, want none (lead uses server-side upsert)", c.posts)
	}
}

// TestNovelUpsertPreviewNoNetwork verifies the default path previews and exits
// 0 without network, even under the verifier.
func TestNovelUpsertPreviewNoNetwork(t *testing.T) {
	t.Setenv(cliutil.VerifyEnvVar, "1")
	dir := t.TempDir()
	file := filepath.Join(dir, "rows.json")
	if err := os.WriteFile(file, []byte(`[{"name":"Ann","email":"ann@x.com"}]`), 0o600); err != nil {
		t.Fatal(err)
	}
	cmd := RootCmd()
	var out bytes.Buffer
	cmd.SetArgs([]string{"upsert", "person", "--match", "email", "--file", file})
	cmd.SetOut(&out)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("upsert preview error = %v", err)
	}
	if !strings.Contains(out.String(), "PREVIEW") {
		t.Errorf("preview output missing PREVIEW marker: %q", out.String())
	}
}

